headStyle:
body { font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif; line-height: 1.6; max-width: 800px; margin: auto; padding: 20px; color: #333; }
        h1 { color: #222; border-bottom: 2px solid #eee; padding-bottom: 10px; }
        .meta { background: #f8f9fa; padding: 15px; border-radius: 8px; margin-bottom: 20px; display: flex; gap: 20px; font-size: 0.9em; }
        .ingredients { background: #fffaf0; padding: 20px; border-radius: 8px; border: 1px solid #ffe4b5; margin-bottom: 20px; }
        .ingredients h2 { margin-top: 0; font-size: 1.2em; color: #8b4513; }
        .ingredients ul { list-style: none; padding: 0; }
        .ingredients li { margin-bottom: 5px; padding-left: 20px; position: relative; }
        .ingredients li::before { content: "□"; position: absolute; left: 0; color: #ffa500; }
        .steps { counter-reset: step-counter; }
        .step { margin-bottom: 20px; padding-left: 40px; position: relative; }
        .step::before { content: counter(step-counter); counter-increment: step-counter; position: absolute; left: 0; top: 0; width: 30px; height: 30px; background: #1976d2; color: #fff; border-radius: 50%; display: flex; align-items: center; justify-content: center; font-weight: bold; }
        .quantity { font-weight: 700; color: #c2185b; }
        .heat { font-weight: 700; color: #d32f2f; }
        .portioning { background: #e3f2fd; padding: 20px; border-radius: 8px; border: 1px solid #bbdefb; }
